    "properties": {
        "state": {"type": "string", "description": "Filter by state: new_session, opening_control, opened, closing_control, closed"}
    }
}

{
    "type": "object",
    "properties": {
        "config_name": {"type": "string", "description": "Name of the POS configuration/register to open"}
    }
}

{
    "type": "object",
    "properties": {
        "config_name": {"type": "string", "description": "Name of the POS configuration/register to close"}
    }
}

{
    "type": "object",
    "properties": {
        "invoice_name": {"type": "string", "description": "Invoice reference number (e.g. INV/2026/00042)"},
        "partner_name": {"type": "string", "description": "Customer name if no invoice reference"}
    }
}

{
    "type": "object",
    "properties": {
        "partner_name": {"type": "string", "description": "Filter by customer/vendor name"},
        "date_filter": {"type": "string", "description": "Date range: today, this_week, this_month"}
    }
}

{
    "type": "object",
    "required": ["invoice_name"],
    "properties": {
        "invoice_name": {"type": "string", "description": "Invoice reference to pay"},
        "amount": {"type": "number", "description": "Payment amount (defaults to invoice balance)"},
        "payment_date": {"type": "string", "format": "date", "description": "Payment date (YYYY-MM-DD)"}
    }
}

{
    "type": "object",
    "properties": {
        "account_name": {"type": "string", "description": "Account name or code to check balance for"}
    }
}

{
    "type": "object",
    "properties": {
        "filter": {"type": "string", "description": "Filter: unpaid, overdue, draft, all"},
        "partner_name": {"type": "string", "description": "Filter by vendor name"}
    }
}

{
    "type": "object",
    "required": ["name"],
    "properties": {
        "name": {"type": "string", "description": "Employee full name"},
        "job_title": {"type": "string", "description": "Job title"},
        "department_name": {"type": "string", "description": "Department name"},
        "work_email": {"type": "string", "description": "Work email address"},
        "work_phone": {"type": "string", "description": "Work phone number"}
    }
}

{
    "type": "object",
    "required": ["employee_name"],
    "properties": {
        "employee_name": {"type": "string", "description": "Employee to update"},
        "job_title": {"type": "string", "description": "New job title"},
        "department_name": {"type": "string", "description": "New department"},
        "work_email": {"type": "string", "description": "New work email"},
        "work_phone": {"type": "string", "description": "New work phone"}
    }
}

{
    "type": "object",
    "required": ["channel_name"],
    "properties": {
        "channel_name": {"type": "string", "description": "Name of the channel to look up"}
    }
}

{
    "type": "object",
    "required": ["name"],
    "properties": {
        "name": {"type": "string", "description": "Channel name"},
        "description": {"type": "string", "description": "Channel description"},
        "channel_type": {"type": "string", "description": "Type: channel or group (default: channel)"}
    }
}

{
    "type": "object",
    "required": ["channel_name", "user_name"],
    "properties": {
        "channel_name": {"type": "string", "description": "Channel name to add the user to"},
        "user_name": {"type": "string", "description": "User or employee name to add"}
    }
}

{
    "type": "object",
    "properties": {
        "channel_name": {"type": "string", "description": "Channel name to fetch messages from"},
        "limit": {"type": "integer", "description": "Number of messages to return (default 20)"}
    }
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member to award points to"},
        "amount": {"type": "integer", "description": "Number of points to award"},
        "note": {"type": "string", "description": "Reason for the award (optional)"}
    },
    "required": ["member_name", "amount"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member to deduct points from"},
        "amount": {"type": "integer", "description": "Number of points to deduct"},
        "note": {"type": "string", "description": "Reason for the deduction (optional)"}
    },
    "required": ["member_name", "amount"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member to add the note to"},
        "note": {"type": "string", "description": "Text of the note to add"}
    },
    "required": ["member_name", "note"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member with the failed billing"}
    },
    "required": ["member_name"]
}

{
    "type": "object",
    "properties": {
        "template_name": {"type": "string", "description": "Name of the class template"},
        "horizon_days": {"type": "integer", "description": "Days ahead to generate (default 30)"}
    },
    "required": ["template_name"]
}

{
    "type": "object",
    "properties": {
        "belt_color": {"type": "string", "description": "Belt color or rank name to filter by (e.g. blue, white, black, purple)"},
        "belt_name": {"type": "string", "description": "Alias for belt_color"}
    }
}

{
    "type": "object",
    "properties": {
        "session_id": {"type": "integer", "description": "Specific session ID to check"},
        "session_name": {"type": "string", "description": "Session or class name to filter by"},
        "class_name": {"type": "string", "description": "Alias for session_name"}
    }
}

{
    "type": "object",
    "properties": {
        "test_id": {"type": "integer", "description": "ID of the belt test"},
        "test_name": {"type": "string", "description": "Name of the belt test"},
        "date": {"type": "string", "format": "date", "description": "Date of the belt test (YYYY-MM-DD)"},
        "program_name": {"type": "string", "description": "Program to filter by (e.g. BJJ, Taekwondo)"}
    }
}

{
    "type": "object",
    "properties": {
        "session_id": {"type": "integer", "description": "Specific session ID"},
        "session_name": {"type": "string", "description": "Session or class name"},
        "class_name": {"type": "string", "description": "Alias for session_name"},
        "date": {"type": "string", "format": "date", "description": "Date to check (YYYY-MM-DD, defaults to today)"}
    }
}

{
    "type": "object",
    "properties": {
        "program_name": {"type": "string", "description": "Program to filter by (e.g. BJJ, Taekwondo)"},
        "threshold_pct": {"type": "number", "description": "Minimum completion percentage (default 100 = fully eligible)", "default": 100}
    }
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Filter by member name (optional)"},
        "limit": {"type": "integer", "description": "Number of sessions to return (default 5)"}
    }
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Filter by member name (optional)"},
        "limit": {"type": "integer", "description": "Number of sessions to return (default 5)"}
    }
}

{
    "type": "object",
    "properties": {
        "ready_only": {"type": "boolean", "description": "If true, only return members who are ready to test (default false)"}
    }
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member to enroll"},
        "course_name": {"type": "string", "description": "Course or class name (optional — uses member's current course if omitted)"}
    },
    "required": ["member_name"]
}
